{
  "name": "Senior Health Insurance Program (SHIP)",
  "eligibility": {
    "age": null,
    "income_limits": "No income limits; available to all Medicare-eligible individuals (typically age 65+, or younger with certain disabilities), their family members, and caregivers[2][6].",
    "asset_limits": "No asset limits[2][6].",
    "other_requirements": ["Must be Medicare-eligible or a family member/caregiver of a Medicare-eligible person[2][6]"]
  },
  "benefits": {
    "type": "advocacy",
    "value": "Free, personalized one-on-one counseling on Medicare Parts A/B/D, Medicare Advantage, Medigap, long-term care insurance, Medicare Savings Programs, prescription drug assistance, Medicaid, appeals, denied claims, bill management, and plan comparisons; referrals, printed materials, public education; no sales of insurance products[2][4][6].",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: 1-800-333-2433[3][7]", "Website: Minnesota Senior LinkAge Line (via mn.gov or shiphelp.org for local contacts)[3][7]", "In-person: Local offices via Senior LinkAge Line referral (e.g., Minnesota Board on Aging, 540 Cedar Street, P.O. Box 64976, St. Paul, MN 55164-0976)[3]"],
    "processing_time": "Immediate counseling appointment scheduling; no formal processing as it's counseling service[6].",
    "waitlist": null,
    "forms": ["No specific forms required; contact for appointment[6]"],
    "documents": ["No documents needed for initial counseling; Medicare card or related info helpful for specific advice[6]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": null,
    "regional_variations": "Delivered through local network of over 2,200 agencies including area agencies on aging; local counselors via statewide Senior LinkAge Line referrals; no service differences noted[3][4][7].",
    "offices_or_providers": ["Minnesota Board on Aging/Senior LinkAge Line (statewide coordination); local Aging Pathways offices[3][7]"]
  },
  "official_source": "https://mn.gov/boardonaging/ (Senior LinkAge Line via Minnesota Board on Aging); CMS contact: https://www.cms.gov/contacts/minnesota-state-health-insurance-assistance-programsenior-linkage-line[3]",
  "gotchas": ["Not a health insurance or financial aid program itself—provides free counseling only, not coverage or payments[2][4][6]", "Counselors are unbiased and do not sell insurance[2][4]", "Confused with Minnesota Senior Health Options (MSHO), a separate managed care program for MA/Medicare dual eligibles age 65+[1][8]", "Services for Medicare beneficiaries and families, not direct medical care[2]"],
  "data_shape_notes": "no income/asset test; counseling/advocacy only; statewide with local delivery network; often misidentified as insurance coverage program"
}

{
  "name": "Senior Community Service Employment Program (SCSEP)",
  "eligibility": {
    "age": 55,
    "income_limits": "Family income no more than 125% of the federal poverty level. Exact dollar amounts vary annually and by household size; for example, for a family of 1 it was approximately $14,850 (based on 2020 data—check current HHS poverty guidelines for 2026 figures). No specific Minnesota table provided in sources[1][4][5][7].",
    "asset_limits": "No asset limits mentioned in sources.",
    "other_requirements": ["Unemployed", "Low employment prospects", "U.S. citizen or legally eligible to work", "Priority: Veterans and qualified spouses first, then individuals over 65, with disabilities, low literacy, limited English proficiency, rural residents, homeless/at risk, or prior American Job Center users[4][5]"]
  },
  "benefits": {
    "type": "employment",
    "value": "Part-time community service work-based job training averaging 20 hours per week at nonprofit organizations, schools, hospitals, senior centers, day care, etc. Paid the highest of federal, state, or local minimum wage. Includes skills development, career coaching, supportive services, and assistance transitioning to unsubsidized employment[1][2][4][5][6].",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": ["Contact Minnesota Department of Employment and Economic Development (DEED): https://mn.gov/deed/programs-services/dislocated-worker/scsep/index.jsp[1]", "Regional providers: e.g., Minnesota Valley Action Council (MVAC) for Blue Earth, Brown, Faribault, Martin, Nicollet, Watonwan counties—email senior@mnvac.org, phone 507-345-6822, in-person 706 N Victory Dr., Mankato, MN, or SCSEP Application form[6]", "CWI Works operates in Minnesota via subgrantees: Check https://www.cwiworks.org/for-job-seekers/our-programs/scsep/scsep-near-you/scsep-in-minnesota/[8]", "MET, Inc.: https://www.metinc.org/senior-employment-program[2]", "American Job Centers for employment assistance[4][5]"],
    "processing_time": "Not specified in sources.",
    "waitlist": "Possible regional waitlists implied by provider-specific operations and past furloughs (e.g., East Side Neighborhood Services note)[3]; varies by provider.",
    "forms": ["SCSEP Application (e.g., via MVAC)[6]"],
    "documents": ["Proof of age, income verification (to confirm ≤125% FPL), unemployment status, veteran status if applicable. Specific list not detailed—prepare tax returns, pay stubs, ID[general inference from program type]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Available statewide but operated through grantees/subgrantees; some providers county-specific (e.g., MVAC in 6 southern counties)[6]",
    "regional_variations": "Different subgrantees/providers by region (e.g., CWI Works network, MVAC in Mankato area, MET Inc., formerly East Side Neighborhood Services in Hennepin)[2][3][6][8]; potential differences in wait times, worksites, contacts.",
    "offices_or_providers": ["MN DEED (state admin)[1]", "Minnesota Valley Action Council (southern counties)[6]", "CWI Works subgrantees statewide[5][8]", "MET, Inc.[2]"]
  },
  "official_source": "https://mn.gov/deed/programs-services/dislocated-worker/scsep/index.jsp",
  "gotchas": ["Temporary training program, not permanent employment—goal is transition to unsubsidized jobs[1][4]", "Income limit strictly 125% FPL (updates yearly—verify current)[4][5]", "Priority enrollment for veterans/65+/disabilities means others may wait longer[4][5]", "Operated by multiple grantees, not centralized—must contact local provider[3][6][8]", "Past disruptions like furloughs possible[3]", "Hennepin County example specifies residency there for that provider[3]"],
  "data_shape_notes": "Federally funded via grantees/subgrantees with regional providers in MN; income at 125% FPL (no table); priority tiers affect access; not uniform statewide administration"
}

{
  "name": "Legal Assistance for Seniors",
  "eligibility": {
    "age": 60,
    "income_limits": "No strict means test or dollar amounts specified; prioritized for those with greatest social and economic need, but services available to seniors 60+ regardless of income level in some programs[1][3][4][8]",
    "asset_limits": "No asset limits or exclusions mentioned",
    "other_requirements": ["Civil legal issues only (e.g., elder abuse, public benefits, housing); criminal or personal injury cases ineligible[1][4]", "Focus on low-income or greatest need, but no formal income test for seniors[3][4]"]
  },
  "benefits": {
    "type": "service",
    "value": "Civil legal services including advice, brief services, full representation for elder abuse, assisted living/nursing home discharges, public benefits (food support, cash assistance, Social Security, Medical Assistance, home care reductions), debtor/creditor issues, housing, debt collection[1][3][4][6]",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": ["Online application at mylegalaid.org[4][10]", "Statewide intake phone: 1-877-MY-MN-LAW (1-877-696-6529)[8]", "Mid-Minnesota Legal Aid: (877) 696-6529 or (800) 292-4150 for disability[4][5]", "Southern Minnesota Regional Legal Services: (888) 575-2954[5]", "LawHelpMN.org for screening and online application[8]", "In-person at regional offices (e.g., Mid-Minnesota Legal Aid Minneapolis: 111 North 5th Street, Suite 100, Minneapolis; St. Cloud: 110 6th Ave S, Ste 200)[4][5]"],
    "processing_time": "Not specified",
    "waitlist": null,
    "forms": ["Online application via mylegalaid.org or LawHelpMN.org"],
    "documents": ["Not explicitly listed; prepare details on income, legal issue, and personal situation for intake screening"]
  },
  "geography": {
    "statewide": false,
    "restrictions": "Delivered through regional legal aid organizations covering specific counties; e.g., Mid-Minnesota Legal Aid serves 20 central counties plus seniors 60+ in additional counties (Benton, Chisago, Isanti, Mille Lacs, Morrison, Sherburne, Stearns, Todd, Wright, Cass, Crow Wing, Kanabec, Pine, Wadena); Southern Minnesota Regional Legal Services in southern areas[4][5][10]",
    "regional_variations": "Different regional providers (e.g., Mid-Minnesota Legal Aid, Southern Minnesota Regional Legal Services, Legal Services of Northwest Minnesota, Justice North) with varying offices, phone lines, and county coverage; intake routed by zip code[2][4][5][8]",
    "offices_or_providers": ["Mid-Minnesota Legal Aid (mylegalaid.org)[1][4][5][10]", "Southern Minnesota Regional Legal Services (smrls.org)[3][5]", "Legal Services of Northwest Minnesota (Moorhead)[2]", "Justice North (Duluth)[2]", "Minnesota Elder Justice Center (elderjusticemn.org)[7]"]
  },
  "official_source": "https://mylegalaid.org/how-we-help/seniors/",
  "gotchas": ["Not a single statewide program but coordinated regional legal aid societies; eligibility screening required even for seniors[8]", "Prioritized for greatest need, so not all seniors get full representation[1][3]", "Excludes criminal, personal injury cases[4]", "Services vary by region and provider availability[4][5]", "Call statewide line for routing to avoid wrong office[8]"],
  "data_shape_notes": "Decentralized across regional legal aid providers with county-specific coverage; no strict income/asset tests for seniors 60+ but priority-based; multiple intake points routed centrally"
}

{
  "name": "Long-Term Care Ombudsman Program",
  "eligibility": {
    "age": null,
    "income_limits": "No income limits; services are free and available to all regardless of financial status.",
    "asset_limits": "No asset limits; no financial tests apply.",
    "other_requirements": ["Must be an adult needing or receiving long-term care services in Minnesota.", "Typically residents of nursing homes, assisted living, residential care communities, board and care homes, home care, housing with services (HWS), or hospice recipients.", "Available to prospective residents and families seeking information or advocacy.", "Consent from the resident is required for investigations or actions (or determination of resident's wishes if filed by others)."][4][2][3][7]
  },
  "benefits": {
    "type": "advocacy",
    "value": "Advocacy services including investigating and resolving complaints (e.g., rights violations ~40%, quality of care ~35%, quality of life ~10%, public benefits/legal/licensing ~15%); problem-solving; education on rights and resources; regular facility visits by volunteers (6 hours monthly per site); system improvements via policy changes; access to private meetings with consumers; all services free.",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: Contact regional ombudsman via state office (specific numbers on mn.gov/ooltc).", "Website: mn.gov/ooltc (new site for resources, contacts, and to submit concerns).", "In-person: Regional ombudsman offices statewide.", "Other: Volunteers and staff in facilities; families can contact directly for assistance."],
    "processing_time": "Not specified; focuses on responsive advocacy rather than formal processing.",
    "waitlist": null,
    "forms": ["No specific forms mentioned; complaints and requests handled via phone, website, or direct contact."],
    "documents": ["Resident consent if applicable; details of complaint or concern (e.g., facility name, issue description); no financial documents required."]
  },
  "geography": {
    "statewide": true,
    "restrictions": "None; serves all Minnesota long-term care settings.",
    "regional_variations": "Delivered through regional ombudsman offices designated by Minnesota Board on Aging (MBA); volunteers assigned to specific nursing homes or HWS residences; contact varies by region but uniform services.",
    "offices_or_providers": ["Office of Ombudsman for Long-Term Care (OOLTC), a service of the Minnesota Board on Aging (MBA); regional ombudsman sub-divisions statewide."]
  },
  "official_source": "https://mn.gov/ooltc/",
  "gotchas": ["Not a healthcare or financial aid program—purely advocacy for resolving complaints and rights issues; requires resident consent for actions; volunteers work in coordination with regional staff, not independently; free of conflicts of interest for all providers; people may miss that it covers home care, HWS, and assisted living beyond just nursing homes; prospective residents and families qualify for info and advocacy."],
  "data_shape_notes": "no income test; advocacy-only (no financial benefits, hours, or tiers); statewide with regional delivery; consent-driven; covers broad long-term care settings including non-residential services."
}

{
  "name": "Minnesota Aging Pathways (formerly Senior LinkAge Line)",
  "eligibility": {
    "age": 60,
    "income_limits": "No specific income limits for core information and referral services; available free to all older adults and caregivers. For connected long-term care services (e.g., resource coordination), eligibility is determined by county social service offices or managed care organizations based on income and asset guidelines, but exact dollar amounts not specified in program details.",
    "asset_limits": "No asset limits for core services. For linked public long-term care programs, assets follow Medicaid rules where applicable (e.g., primary home exempt if equity ≤$730,000 in 2025, household items, personal effects, one vehicle exempt; look-back rule applies for transfers).",
    "other_requirements": ["Minnesota resident", "Older adults (60+), caregivers, or family members seeking support to remain/return home", "For resource coordination: at risk of nursing home placement or needing community services", "No functional need required for initial info/referral"]
  },
  "benefits": {
    "type": "service",
    "value": "Free information and assistance (I&A) on aging services, Medicare counseling, resource coordination (person-centered plans to live at home, service connections, follow-up), preadmission screening (PAS) for nursing facility admissions, referrals to long-term care options, Minnesota Aging and Disability Resources exploration. No fixed dollar amounts or hours; services tailored via phone consultation and plans.",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: 800-333-2433 (Mon-Fri 8:00 a.m. to 4:30 p.m.; press option 1 for housing)", "Online referral: www.sllreferral.org (for providers, facilities, individuals/caregivers)", "Referrals from nursing facilities, hospitals, assisted living, clinics, home care, hospice, ombudsman"],
    "processing_time": "Phone assistance immediate; resource coordination involves discussion and plan development (timeline not specified); PAS review leads to in-person assessment or call as needed.",
    "waitlist": null,
    "forms": ["Preadmission Screening (PAS) submitted by health care providers", "Online referral form at www.sllreferral.org"],
    "documents": ["No specific documents for initial call or referral; for linked services (e.g., PAS, long-term care), may need MDS assessments, medical records, or county eligibility docs as referred"]
  },
  "geography": {
    "statewide": true,
    "restrictions": null,
    "regional_variations": "Services delivered statewide via central phone line; local county social service offices or managed care organizations handle eligibility for funded long-term care referrals; area agencies on aging partner but no specified wait time or provider differences.",
    "offices_or_providers": ["Statewide service; referrals triage to local lead agencies or county offices as needed"]
  },
  "official_source": "https://mn.gov/aging-pathways/",
  "gotchas": ["Not a direct service provider—connects to services but does not fund or deliver them (eligibility for actual benefits via counties/Medicaid)", "Required for certain transitions (e.g., PAS mandatory for nursing facility admissions, long-term care options counseling for assisted living)", "Free I&A open to all, but deeper resource coordination targeted to those 60+ at home or transitioning", "Medicare counseling limited to those eligible for Medicare benefits", "Referrals often initiated by providers/facilities, not always self-referral"],
  "data_shape_notes": "no income test for core I&A; eligibility for linked services via county determination; statewide phone hub with local referral triage; formerly Senior LinkAge Line, now rebranded"
}
